<span class="line"><span class="token builtin class-name">echo</span> <span class="token string">"deb https://packages.adoptium.net/artifactory/deb <span class="token variable"><span class="token variable">$(</span><span class="token function">awk</span> <span class="token parameter variable">-F</span><span class="token operator">=</span> <span class="token string">'/^VERSION_CODENAME/{print$2}'</span> /etc/os-release<span class="token variable">)</span></span> main"</span> <span class="token operator">|</span> <span class="token function">tee</span> /etc/apt/sources.list.d/adoptium.list<span class="token punctuation">;</span></span>
